// Navigate to the actual text content
let textContent;
if (response.candidates && response.candidates[0]) {
  // Standard Gemini response structure
  textContent = response.candidates[0].content.parts[0].text;
} else if (Array.isArray(response) && response[0]) {
  // Array response structure (your case)
  textContent = response[0].content.parts[0].text;
} else if (response.content && response.content.parts) {
  // Direct content structure
  textContent = response.content.parts[0].text;
} else {
  throw new Error('Unexpected response structure: ' + JSON.stringify(response));
}

// Extract JSON from response (handle markdown code blocks)
