// Get original webhook data
const webhookData = $('Webhook').first().json;

// The merge node outputs 2 items in an array
// Item 0 = Parse Text Analysis output
// Item 1 = Parse Image Analysis output
const textData = items[0].json;
const imageData = items[1].json;

// Define thresholds
const thresholds = {
  auto_approve: 80,
  needs_review: 40
};

// Extract scores
const textScore = textData.text_approval_percentage || 0;
const imageScore = imageData.image_approval_percentage || 0;

// Calculate final score (average of both)
const finalScore = Math.round((textScore + imageScore) / 2);

// Determine final decision
let finalDecision;
let decisionReason;

// Check if either AI explicitly rejected
const textRejects = textData.text_recommendation === 'REJECT' || 
                   (textData.text_issues && textData.text_issues.length > 0);
const imageRejects = imageData.image_recommendation === 'REJECT' || 
                    (imageData.image_issues && imageData.image_issues.length > 0);

if (textRejects || imageRejects) {
  finalDecision = "AUTO_REJECTED";
  decisionReason = "Content violates platform guidelines";
} else if (finalScore >= thresholds.auto_approve) {
  finalDecision = "AUTO_APPROVED";
  decisionReason = "Content meets all guidelines with high confidence";
} else if (finalScore >= thresholds.needs_review) {
  finalDecision = "NEEDS_REVIEW";
  decisionReason = "Content requires human review due to moderate confidence";
} else {
  finalDecision = "AUTO_REJECTED";
  decisionReason = "Low confidence score indicates potential issues";
}

// Combine all issues and concerns
const allIssues = [
  ...(textData.text_issues || []),
  ...(imageData.image_issues || [])
];

const allConcerns = [
  ...(textData.text_concerns || []),
  ...(imageData.image_concerns || [])
];

// Prepare combined reasoning
const combinedReasoning = `
=== TEXT ANALYSIS ===
Decision: ${textData.text_recommendation}
Confidence: ${textScore}%
Reasoning: ${textData.text_analysis}

=== IMAGE ANALYSIS ===
Decision: ${imageData.image_recommendation}
Confidence: ${imageScore}%
Reasoning: ${imageData.image_analysis}
Image Description: ${imageData.image_description || 'Not provided'}

=== ISSUES FOUND ===
${allIssues.length > 0 ? '• ' + allIssues.join('\n• ') : 'None'}

=== CONCERNS ===
${allConcerns.length > 0 ? '• ' + allConcerns.join('\n• ') : 'None'}
`;

// Return single item (not array) for the next nodes
return [{
  json: {
    // Original data from webhook
    post_id: webhookData.post_id,
    title: webhookData.title,
    description: webhookData.description,
    image_url: webhookData.image_url,
    category: webhookData.category || 'Unknown',
    user_id: webhookData.user_id || 'Unknown',

    // Text analysis results
    text_analysis: textData.text_analysis,
    text_approval_percentage: textScore,
    text_recommendation: textData.text_recommendation,
    text_issues: textData.text_issues || [],
    text_concerns: textData.text_concerns || [],

    // Image analysis results
    image_analysis: imageData.image_analysis,
    image_approval_percentage: imageScore,
    image_recommendation: imageData.image_recommendation,
    image_description: imageData.image_description || 'Not provided',
    image_issues: imageData.image_issues || [],
    image_concerns: imageData.image_concerns || [],

    // Final decision
    final_score: finalScore,
    final_decision: finalDecision,
    decision_reason: decisionReason,
    combined_reasoning: combinedReasoning.trim(),
    issues_found: allIssues,
    concerns_found: allConcerns,

    // Metadata
    timestamp: new Date().toISOString(),
    processed_at: new Date().toLocaleString('en-US', { timeZone: 'UTC' })
  }
}];
